	private void OpenCreateWindow()
	{
		if (_createWindow != null)
		{
			((BaseWindow)_createWindow).OpenCentered();
			return;
		}
		_createWindow = new MiniGameLobbyCreateWindow();
		_createWindow.SetCustomArenas(_customArenas);
		_createWindow.OnCreateLobby += delegate(string name, string gameId, string submodeId, string mapId, int rounds, int maxPlayers, bool locked, string password)
