			this.OnCreateLobby?.Invoke(name, gameId, submodeId, mapId, rounds, maxPlayers, locked, password);
		};
		((BaseWindow)_createWindow).OnClose += delegate
		{
			_createWindow = null;
		};
		((BaseWindow)_createWindow).OpenCentered();
	}

	public void UpdateLobbyList(List<MiniGameLobbyListEntry> lobbies)
	{
