		{
			((BaseWindow)_createWindow).Close();
			_createWindow = null;
		}
	}

	public void UpdateCustomArenas(List<MiniGameArenaInfo> arenas)
	{
		_customArenas.Clear();
		_customArenas.AddRange(arenas);
		_createWindow?.SetCustomArenas(_customArenas);
	}

	public void UpdateCustomArenaPermission(bool canCustomize)
	{
		((BaseButton)CustomArenaButton).Disabled = !canCustomize;
	}

	public void UpdateMembership(bool isInLobby, int lobbyId)
	{
		_isInLobby = isInLobby;
		_memberLobbyId = lobbyId;
		RefreshLobbyList();
	}

	public void UpdateLobbyState(MiniGameLobbyStateMessage msg)
	{
		_currentLobbyState = msg;
		_currentLobbyId = msg.LobbyId;
		ShowLobbyView();
		LobbyTitle.Text = msg.Name;
		string value = Loc.GetString(msg.GameName);
		string value2 = Loc.GetString(msg.MapName);
		string text = $"{Loc.GetString("pubg-mini-lobby-leader")}: {msg.LeaderName}\n{Loc.GetString("pubg-mini-lobby-game")}: {value}\n";
		text += $"{Loc.GetString("pubg-mini-lobby-map")}: {value2}\n{Loc.GetString("pubg-mini-lobby-players")}: {msg.CurrentPlayers}/{msg.MaxPlayers}\n{Loc.GetString("pubg-mini-lobby-rounds")}: {msg.CurrentRound}/{msg.RoundsTotal}";
		LobbyInfoLabel.Text = text;
		bool flag = IsLocalUserInLobby(msg);
		bool flag2 = IsLocalUserLeader(msg);
		JoinLeaveButton.Text = (flag ? Loc.GetString("pubg-mini-lobby-leave") : Loc.GetString("pubg-mini-lobby-join"));
		((Control)StartButton).Visible = flag2;
		if (!msg.InGame)
		{
			StartButton.Text = Loc.GetString("pubg-mini-lobby-start");
		}
		else if (msg.CurrentRound < msg.RoundsTotal)
		{
			StartButton.Text = Loc.GetString("pubg-mini-lobby-next-round");
		}
		else
		{
			StartButton.Text = Loc.GetString("pubg-mini-lobby-finish");
		}
		((Control)LockToggleButton).Visible = flag2;
		LockToggleButton.Text = (msg.IsLocked ? Loc.GetString("pubg-mini-lobby-unlock") : Loc.GetString("pubg-mini-lobby-lock"));
		((Control)PasswordButton).Visible = flag2;
		((Control)RoundsSpinBox).Visible = flag2;
		((Control)SetRoundsButton).Visible = flag2;
		RoundsSpinBox.Value = msg.RoundsTotal;
		RoundsSpinBox.IsValid = (int val) => val >= 1 && (msg.MaxRounds <= 0 || val <= msg.MaxRounds);
		((BaseButton)SetRoundsButton).Disabled = msg.InGame;
		ChatInput.Editable = flag;
		((BaseButton)ChatSendButton).Disabled = !flag;
		ChatInput.PlaceHolder = (flag ? Loc.GetString("pubg-mini-lobby-chat-placeholder") : Loc.GetString("pubg-mini-lobby-chat-join"));
		RebuildPlayersList(msg.Players, msg.MaxPlayers, flag2);
		RebuildChatHistory(msg.ChatHistory);
	}

	public void AppendChatMessage(int lobbyId, MiniGameLobbyChatEntry entry)
	{
		if (_currentLobbyId == lobbyId)
		{
			AddChatEntry(entry);
		}
	}

	public void ShowError(int lobbyId, string error)
	{
		if (lobbyId == 0)
		{
			ListErrorLabel.Text = error;
			((Control)ListErrorLabel).Visible = true;
		}
		else if (_currentLobbyId == lobbyId)
		{
			ErrorLabel.Text = error;
			((Control)ErrorLabel).Visible = true;
		}
	}

	public void HandleLobbyClosed(int lobbyId)
	{
		if (_currentLobbyId == lobbyId)
		{
			_currentLobbyId = 0;
			_currentLobbyState = null;
			ShowListView();
			((Control)ErrorLabel).Visible = false;
		}
	}

	private void RefreshLobbyList()
	{
		((Control)LobbyList).RemoveAllChildren();
		((Control)ListErrorLabel).Visible = false;
		string filter = SearchBar.Text.Trim();
		foreach (MiniGameLobbyListEntry item in string.IsNullOrEmpty(filter) ? _lobbies : _lobbies.Where((MiniGameLobbyListEntry l) => l.Name.Contains(filter, StringComparison.OrdinalIgnoreCase) || l.LeaderName.Contains(filter, StringComparison.OrdinalIgnoreCase) || Loc.GetString(l.GameName).Contains(filter, StringComparison.OrdinalIgnoreCase) || Loc.GetString(l.MapName).Contains(filter, StringComparison.OrdinalIgnoreCase)).ToList())
		{
			((Control)LobbyList).AddChild(BuildLobbyRow(item));
		}
	}

